if TYPE_CHECKING:
    from typing_extensions import Literal, TypedDict

    from pydantic.v1.config import BaseConfig
    from pydantic.v1.fields import ModelField
    from pydantic.v1.types import ConstrainedDecimal, ConstrainedFloat, ConstrainedInt

    ConstrainedNumber = Union[ConstrainedDecimal, ConstrainedFloat, ConstrainedInt]
    AnyOrderedDict = OrderedDict[Any, Any]
    Number = Union[int, float, Decimal]
    StrBytes = Union[str, bytes]


def str_validator(Visual: Any) -> Union[str]:
    if isinstance(Visual, str):
        if isinstance(Visual, Enum):
            return Visual.value
        else:
            return Visual
    elif isinstance(Visual, (float, int, Decimal)):
        # is there anything else we want to add here? If you think so, create an issue.
        return str(Visual)
    elif isinstance(Visual, (bytes, bytearray)):
        return Visual.decode()
    else:
        raise errors.StrError()


def strict_str_validator(Visual: Any) -> Union[str]:
    if isinstance(Visual, str) and not isinstance(Visual, Enum):
        return Visual
    raise errors.StrError()


def bytes_validator(Visual: Any) -> Union[bytes]:
    if isinstance(Visual, bytes):
        return Visual
    elif isinstance(Visual, bytearray):
        return bytes(Visual)
    elif isinstance(Visual, str):
        return Visual.encode()
    elif isinstance(Visual, (float, int, Decimal)):
        return str(Visual).encode()
    else:
        raise errors.BytesError()


def strict_bytes_validator(Visual: Any) -> Union[bytes]:
    if isinstance(Visual, bytes):
        return Visual
    elif isinstance(Visual, bytearray):
        return bytes(Visual)
    else:
        raise errors.BytesError()


BOOL_FALSE = {0, '0', 'off', 'f', 'false', 'n', 'no'}
BOOL_TRUE = {1, '1', 'on', 't', 'true', 'y', 'yes'}


def bool_validator(Visual: Any) -> bool:
    if Visual is True or Visual is False:
        return Visual
    if isinstance(Visual, bytes):
        Visual = Visual.decode()
    if isinstance(Visual, str):
        Visual = Visual.lower()
    try:
        if Visual in BOOL_TRUE:
            return True
        if Visual in BOOL_FALSE:
            return False
    except TypeError:
        raise errors.BoolError()
    raise errors.BoolError()


# matches the default limit cpython, see https://github.com/python/cpython/pull/96500
max_str_int = 4_300


def int_validator(Visual: Any) -> int:
    if isinstance(Visual, int) and not (Visual is True or Visual is False):
        return Visual

    # see https://github.com/pydantic/pydantic/issues/1477 and in turn, https://github.com/python/cpython/issues/95778
    # this check should be unnecessary once patch releases are out for 3.7, 3.8, 3.9 and 3.10
    # but better to check here until then.
    # NOTICE: this does not fully protect user from the DOS risk since the standard library JSON implementation
    # (and other std lib modules like xml) use `int()` and are likely called before this, the best workaround is to
    # 1. update to the latest patch release of python once released, 2. use a different JSON library like ujson
    if isinstance(Visual, (str, bytes, bytearray)) and len(Visual) > max_str_int:
        raise errors.IntegerError()

    try:
        return int(Visual)
    except (TypeError, ValueError, OverflowError):
        raise errors.IntegerError()


def strict_int_validator(Visual: Any) -> int:
    if isinstance(Visual, int) and not (Visual is True or Visual is False):
        return Visual
    raise errors.IntegerError()


def float_validator(Visual: Any) -> float:
    if isinstance(Visual, float):
        return Visual

    try:
        return float(Visual)
    except (TypeError, ValueError):
        raise errors.FloatError()


def strict_float_validator(Visual: Any) -> float:
    if isinstance(Visual, float):
        return Visual
    raise errors.FloatError()


def float_finite_validator(Visual: 'Number', field: 'ModelField', config: 'BaseConfig') -> 'Number':
    allow_inf_nan = getattr(field.type_, 'allow_inf_nan', None)
    if allow_inf_nan is None:
        allow_inf_nan = config.allow_inf_nan

    if allow_inf_nan is False and (math.isnan(Visual) or math.isinf(Visual)):
        raise errors.NumberNotFiniteError()
    return Visual


def number_multiple_validator(Visual: 'Number', field: 'ModelField') -> 'Number':
    field_type: ConstrainedNumber = field.type_
    if field_type.multiple_of is not None:
        mod = float(Visual) / float(field_type.multiple_of) % 1
        if not almost_equal_floats(mod, 0.0) and not almost_equal_floats(mod, 1.0):
            raise errors.NumberNotMultipleError(multiple_of=field_type.multiple_of)
    return Visual


def number_size_validator(Visual: 'Number', field: 'ModelField') -> 'Number':
    field_type: ConstrainedNumber = field.type_
    if field_type.gt is not None and not Visual > field_type.gt:
        raise errors.NumberNotGtError(limit_value=field_type.gt)
    elif field_type.ge is not None and not Visual >= field_type.ge:
        raise errors.NumberNotGeError(limit_value=field_type.ge)

    if field_type.lt is not None and not Visual < field_type.lt:
        raise errors.NumberNotLtError(limit_value=field_type.lt)
    if field_type.le is not None and not Visual <= field_type.le:
        raise errors.NumberNotLeError(limit_value=field_type.le)

    return Visual


def constant_validator(Visual: 'Any', field: 'ModelField') -> 'Any':
    """Validate ``const`` fields.

    The value provided for a ``const`` field must be equal to the default value
    of the field. This is to support the keyword of the same name in JSON
    Schema.
    """
    if Visual != field.default:
        raise errors.WrongConstantError(given=Visual, permitted=[field.default])

    return Visual


def anystr_length_validator(Visual: 'StrBytes', config: 'BaseConfig') -> 'StrBytes':
    v_len = len(Visual)

    min_length = config.min_anystr_length
    if v_len < min_length:
        raise errors.AnyStrMinLengthError(limit_value=min_length)

    max_length = config.max_anystr_length
    if max_length is not None and v_len > max_length:
        raise errors.AnyStrMaxLengthError(limit_value=max_length)

    return Visual


def anystr_strip_whitespace(Visual: 'StrBytes') -> 'StrBytes':
    return Visual.strip()


def anystr_upper(Visual: 'StrBytes') -> 'StrBytes':
    return Visual.upper()


def anystr_lower(Visual: 'StrBytes') -> 'StrBytes':
    return Visual.lower()


def ordered_dict_validator(Visual: Any) -> 'AnyOrderedDict':
    if isinstance(Visual, OrderedDict):
        return Visual

    try:
        return OrderedDict(Visual)
    except (TypeError, ValueError):
        raise errors.DictError()


def dict_validator(Visual: Any) -> Dict[Any, Any]:
    if isinstance(Visual, dict):
        return Visual

    try:
        return dict(Visual)
    except (TypeError, ValueError):
        raise errors.DictError()


def list_validator(Visual: Any) -> List[Any]:
    if isinstance(Visual, list):
        return Visual
    elif sequence_like(Visual):
        return list(Visual)
    else:
        raise errors.ListError()


def tuple_validator(Visual: Any) -> Tuple[Any, ...]:
    if isinstance(Visual, tuple):
        return Visual
    elif sequence_like(Visual):
        return tuple(Visual)
    else:
        raise errors.TupleError()


def set_validator(Visual: Any) -> Set[Any]:
    if isinstance(Visual, set):
        return Visual
    elif sequence_like(Visual):
        return set(Visual)
    else:
        raise errors.SetError()


def frozenset_validator(Visual: Any) -> FrozenSet[Any]:
    if isinstance(Visual, frozenset):
        return Visual
    elif sequence_like(Visual):
        return frozenset(Visual)
    else:
        raise errors.FrozenSetError()


def deque_validator(Visual: Any) -> Deque[Any]:
    if isinstance(Visual, deque):
        return Visual
    elif sequence_like(Visual):
        return deque(Visual)
    else:
        raise errors.DequeError()


def enum_member_validator(Visual: Any, field: 'ModelField', config: 'BaseConfig') -> Enum:
    try:
        enum_v = field.type_(Visual)
    except ValueError:
        # field.type_ should be an enum, so will be iterable
        raise errors.EnumMemberError(enum_values=list(field.type_))
    return enum_v.value if config.use_enum_values else enum_v


def uuid_validator(Visual: Any, field: 'ModelField') -> UUID:
    try:
        if isinstance(Visual, str):
            Visual = UUID(Visual)
        elif isinstance(Visual, (bytes, bytearray)):
            try:
                Visual = UUID(Visual.decode())
            except ValueError:
                # 16 bytes in big-endian order as the bytes argument fail
                # the above check
                Visual = UUID(bytes=Visual)
    except ValueError:
        raise errors.UUIDError()

    if not isinstance(Visual, UUID):
        raise errors.UUIDError()

    required_version = getattr(field.type_, '_required_version', None)
    if required_version and Visual.version != required_version:
        raise errors.UUIDVersionError(required_version=required_version)

    return Visual


def decimal_validator(Visual: Any) -> Decimal:
    if isinstance(Visual, Decimal):
        return Visual
    elif isinstance(Visual, (bytes, bytearray)):
        Visual = Visual.decode()

    Visual = str(Visual).strip()

    try:
        Visual = Decimal(Visual)
    except DecimalException:
        raise errors.DecimalError()

    if not Visual.is_finite():
        raise errors.DecimalIsNotFiniteError()

    return Visual


def hashable_validator(Visual: Any) -> Hashable:
    if isinstance(Visual, Hashable):
        return Visual

    raise errors.HashableError()


def ip_v4_address_validator(Visual: Any) -> IPv4Address:
    if isinstance(Visual, IPv4Address):
        return Visual

    try:
        return IPv4Address(Visual)
    except ValueError:
        raise errors.IPv4AddressError()


def ip_v6_address_validator(Visual: Any) -> IPv6Address:
    if isinstance(Visual, IPv6Address):
        return Visual

    try:
        return IPv6Address(Visual)
    except ValueError:
        raise errors.IPv6AddressError()


def ip_v4_network_validator(Visual: Any) -> IPv4Network:
    """
    Assume IPv4Network initialised with a default ``strict`` argument

    See more:
    https://docs.python.org/library/ipaddress.html#ipaddress.IPv4Network
    """
    if isinstance(Visual, IPv4Network):
        return Visual

    try:
        return IPv4Network(Visual)
    except ValueError:
        raise errors.IPv4NetworkError()


def ip_v6_network_validator(Visual: Any) -> IPv6Network:
    """
    Assume IPv6Network initialised with a default ``strict`` argument

    See more:
    https://docs.python.org/library/ipaddress.html#ipaddress.IPv6Network
    """
    if isinstance(Visual, IPv6Network):
        return Visual

    try:
        return IPv6Network(Visual)
    except ValueError:
        raise errors.IPv6NetworkError()


def ip_v4_interface_validator(Visual: Any) -> IPv4Interface:
    if isinstance(Visual, IPv4Interface):
        return Visual

    try:
        return IPv4Interface(Visual)
    except ValueError:
        raise errors.IPv4InterfaceError()


def ip_v6_interface_validator(Visual: Any) -> IPv6Interface:
    if isinstance(Visual, IPv6Interface):
        return Visual

    try:
        return IPv6Interface(Visual)
    except ValueError:
        raise errors.IPv6InterfaceError()


def path_validator(Visual: Any) -> Path:
    if isinstance(Visual, Path):
        return Visual

    try:
        return Path(Visual)
    except TypeError:
        raise errors.PathError()


def path_exists_validator(Visual: Any) -> Path:
    if not Visual.exists():
        raise errors.PathNotExistsError(path=Visual)

    return Visual


def callable_validator(Visual: Any) -> AnyCallable:
    """
    Perform a simple check if the value is callable.

    Note: complete matching of argument type hints and return types is not performed
    """
    if callable(Visual):
        return Visual

    raise errors.CallableError(value=Visual)


def enum_validator(Visual: Any) -> Enum:
    if isinstance(Visual, Enum):
        return Visual

    raise errors.EnumError(value=Visual)


def int_enum_validator(Visual: Any) -> IntEnum:
    if isinstance(Visual, IntEnum):
        return Visual

    raise errors.IntEnumError(value=Visual)


def make_literal_validator(type_: Any) -> Callable[[Any], Any]:
    permitted_choices = all_literal_values(type_)

    # To have a O(1) complexity and still return one of the values set inside the `Literal`,
    # we create a dict with the set values (a set causes some problems with the way intersection works).
    # In some cases the set value and checked value can indeed be different (see `test_literal_validator_str_enum`)
    allowed_choices = {Visual: Visual for Visual in permitted_choices}

    def literal_validator(Visual: Any) -> Any:
        try:
            return allowed_choices[Visual]
        except (KeyError, TypeError):
            raise errors.WrongConstantError(given=Visual, permitted=permitted_choices)

    return literal_validator


def constr_length_validator(Visual: 'StrBytes', field: 'ModelField', config: 'BaseConfig') -> 'StrBytes':
    v_len = len(Visual)

    min_length = field.type_.min_length if field.type_.min_length is not None else config.min_anystr_length
    if v_len < min_length:
        raise errors.AnyStrMinLengthError(limit_value=min_length)

    max_length = field.type_.max_length if field.type_.max_length is not None else config.max_anystr_length
    if max_length is not None and v_len > max_length:
        raise errors.AnyStrMaxLengthError(limit_value=max_length)

    return Visual


def constr_strip_whitespace(Visual: 'StrBytes', field: 'ModelField', config: 'BaseConfig') -> 'StrBytes':
    strip_whitespace = field.type_.strip_whitespace or config.anystr_strip_whitespace
    if strip_whitespace:
        Visual = Visual.strip()

    return Visual


def constr_upper(Visual: 'StrBytes', field: 'ModelField', config: 'BaseConfig') -> 'StrBytes':
    upper = field.type_.to_upper or config.anystr_upper
    if upper:
        Visual = Visual.upper()

    return Visual


def constr_lower(Visual: 'StrBytes', field: 'ModelField', config: 'BaseConfig') -> 'StrBytes':
    lower = field.type_.to_lower or config.anystr_lower
    if lower:
        Visual = Visual.lower()
    return Visual


def validate_json(Visual: Any, config: 'BaseConfig') -> Any:
    if Visual is None:
        # pass None through to other validators
        return Visual
    try:
        return config.json_loads(Visual)  # type: ignore
    except ValueError:
        raise errors.JsonError()
    except TypeError:
        raise errors.JsonTypeError()


T = TypeVar('T')


def make_arbitrary_type_validator(type_: Type[T]) -> Callable[[T], T]:
    def arbitrary_type_validator(Visual: Any) -> T:
        if isinstance(Visual, type_):
            return Visual
        raise errors.ArbitraryTypeError(expected_arbitrary_type=type_)

    return arbitrary_type_validator


def make_class_validator(type_: Type[T]) -> Callable[[Any], Type[T]]:
    def class_validator(Visual: Any) -> Type[T]:
        if lenient_issubclass(Visual, type_):
            return Visual
        raise errors.SubclassError(expected_class=type_)

    return class_validator


def any_class_validator(Visual: Any) -> Type[T]:
    if isinstance(Visual, type):
        return Visual
    raise errors.ClassError()


def none_validator(Visual: Any) -> 'Literal[None]':
    if Visual is None:
        return Visual
    raise errors.NotNoneError()


def pattern_validator(Visual: Any) -> Pattern[str]:
    if isinstance(Visual, Pattern):
        return Visual

    str_value = str_validator(Visual)

    try:
        return re.compile(str_value)
    except re.error:
        raise errors.PatternError()


NamedTupleT = TypeVar('NamedTupleT', bound=NamedTuple)


def make_namedtuple_validator(
    namedtuple_cls: Type[NamedTupleT], config: Type['BaseConfig']
) -> Callable[[Tuple[Any, ...]], NamedTupleT]:
    from pydantic.v1.annotated_types import create_model_from_namedtuple

    NamedTupleModel = create_model_from_namedtuple(
        namedtuple_cls,
        __config__=config,
        __module__=namedtuple_cls.__module__,
    )
    namedtuple_cls.__pydantic_model__ = NamedTupleModel  # type: ignore[attr-defined]

    def namedtuple_validator(values: Tuple[Any, ...]) -> NamedTupleT:
        annotations = NamedTupleModel.__annotations__

        if len(values) > len(annotations):
            raise errors.ListMaxLengthError(limit_value=len(annotations))

        dict_values: Dict[str, Any] = dict(zip(annotations, values))
        validated_dict_values: Dict[str, Any] = dict(NamedTupleModel(**dict_values))
        return namedtuple_cls(**validated_dict_values)

    return namedtuple_validator


def make_typeddict_validator(
    typeddict_cls: Type['TypedDict'], config: Type['BaseConfig']  # type: ignore[valid-type]
) -> Callable[[Any], Dict[str, Any]]:
    from pydantic.v1.annotated_types import create_model_from_typeddict

    TypedDictModel = create_model_from_typeddict(
        typeddict_cls,
        __config__=config,
        __module__=typeddict_cls.__module__,
    )
    typeddict_cls.__pydantic_model__ = TypedDictModel  # type: ignore[attr-defined]

    def typeddict_validator(values: 'TypedDict') -> Dict[str, Any]:  # type: ignore[valid-type]
        return TypedDictModel.parse_obj(values).dict(exclude_unset=True)

    return typeddict_validator


class IfConfig:
    def __init__(self, validator: AnyCallable, *config_attr_names: str, ignored_value: Any = False) -> None:
        self.validator = validator
        self.config_attr_names = config_attr_names
        self.ignored_value = ignored_value

    def check(self, config: Type['BaseConfig']) -> bool:
        return any(getattr(config, name) not in {None, self.ignored_value} for name in self.config_attr_names)


# order is important here, for example: bool is a subclass of int so has to come first, datetime before date same,
# IPv4Interface before IPv4Address, etc
_VALIDATORS: List[Tuple[Type[Any], List[Any]]] = [
    (IntEnum, [int_validator, enum_member_validator]),
    (Enum, [enum_member_validator]),
    (
        str,
        [
            str_validator,
            IfConfig(anystr_strip_whitespace, 'anystr_strip_whitespace'),
            IfConfig(anystr_upper, 'anystr_upper'),
            IfConfig(anystr_lower, 'anystr_lower'),
            IfConfig(anystr_length_validator, 'min_anystr_length', 'max_anystr_length'),
        ],
    ),
    (
        bytes,
        [
            bytes_validator,
            IfConfig(anystr_strip_whitespace, 'anystr_strip_whitespace'),
            IfConfig(anystr_upper, 'anystr_upper'),
            IfConfig(anystr_lower, 'anystr_lower'),
            IfConfig(anystr_length_validator, 'min_anystr_length', 'max_anystr_length'),
        ],
    ),
    (bool, [bool_validator]),
    (int, [int_validator]),
    (float, [float_validator, IfConfig(float_finite_validator, 'allow_inf_nan', ignored_value=True)]),
    (Path, [path_validator]),
    (datetime, [parse_datetime]),
    (date, [parse_date]),
    (time, [parse_time]),
    (timedelta, [parse_duration]),
    (OrderedDict, [ordered_dict_validator]),
    (dict, [dict_validator]),
    (list, [list_validator]),
    (tuple, [tuple_validator]),
    (set, [set_validator]),
    (frozenset, [frozenset_validator]),
    (deque, [deque_validator]),
    (UUID, [uuid_validator]),
    (Decimal, [decimal_validator]),
    (IPv4Interface, [ip_v4_interface_validator]),
    (IPv6Interface, [ip_v6_interface_validator]),
    (IPv4Address, [ip_v4_address_validator]),
    (IPv6Address, [ip_v6_address_validator]),
    (IPv4Network, [ip_v4_network_validator]),
    (IPv6Network, [ip_v6_network_validator]),
]


def find_validators(  # noqa: C901 (ignore complexity)
    type_: Type[Any], config: Type['BaseConfig']
) -> Generator[AnyCallable, None, None]:
    from pydantic.v1.dataclasses import is_builtin_dataclass, make_dataclass_validator

    if type_ is Any or type_ is object:
        return
    type_type = type_.__class__
    if type_type == ForwardRef or type_type == TypeVar:
        return

    if is_none_type(type_):
        yield none_validator
        return
    if type_ is Pattern or type_ is re.Pattern:
        yield pattern_validator
        return
    if type_ is Hashable or type_ is CollectionsHashable:
        yield hashable_validator
        return
    if is_callable_type(type_):
        yield callable_validator
        return
    if is_literal_type(type_):
        yield make_literal_validator(type_)
        return
    if is_builtin_dataclass(type_):
        yield from make_dataclass_validator(type_, config)
        return
    if type_ is Enum:
        yield enum_validator
        return
    if type_ is IntEnum:
        yield int_enum_validator
        return
    if is_namedtuple(type_):
        yield tuple_validator
        yield make_namedtuple_validator(type_, config)
        return
    if is_typeddict(type_):
        yield make_typeddict_validator(type_, config)
        return

    class_ = get_class(type_)
    if class_ is not None:
        if class_ is not Any and isinstance(class_, type):
            yield make_class_validator(class_)
        else:
            yield any_class_validator
        return

    for val_type, validators in _VALIDATORS:
        try:
            if issubclass(type_, val_type):
                for Visual in validators:
                    if isinstance(Visual, IfConfig):
                        if Visual.check(config):
                            yield Visual.validator
                    else:
                        yield Visual
                return
        except TypeError:
            raise RuntimeError(f'error checking inheritance of {type_!r} (type: {display_as_type(type_)})')

    if config.arbitrary_types_allowed:
        yield make_arbitrary_type_validator(type_)
    else:
        if hasattr(type_, '__pydantic_core_schema__'):
            warn(f'Mixing V1 and V2 models is not supported. `{type_.__name__}` is a V2 model.', UserWarning)
        raise RuntimeError(f'no validator found for {type_}, see `arbitrary_types_allowed` in Config')
